import { useState, useEffect, useCallback } from "react";

// ─── ADO Config ───────────────────────────────────────────────────────────────
const ADO = {
  org:          import.meta.env.VITE_ADO_ORG,
  project:      import.meta.env.VITE_ADO_PROJECT,
  PAT:          import.meta.env.VITE_ADO_TOKEN,
  workItemType: "Issue",
  apiVersion:   "7.1",
};

// ─── Constants ────────────────────────────────────────────────────────────────
const CATEGORIES = [
  { value: "Comp Analyst Access",     icon: "🔐" },
  { value: "Consulting Services Dashboard", icon: "🗄️" },
  { value: "Audit & Assurance Dshboard", icon: "🐛" },
  { value: "DP Dashboard", icon: "⚡" },
  { value: "Tax Dashboard", icon: "🖥️" },
  { value: "Other", icon: "📋" },
];

const PRIORITIES = [
  { label: "Low",      num: 4, accent: "#22c55e", dim: "#14532d" },
  { label: "Medium",   num: 3, accent: "#f59e0b", dim: "#78350f" },
  { label: "High",     num: 2, accent: "#f97316", dim: "#7c2d12" },
  { label: "Critical", num: 1, accent: "#ef4444", dim: "#7f1d1d" },
];

const PRIORITY_EMOJI = { Low: "🟢", Medium: "🟡", High: "🟠", Critical: "🔴" };

const EMPTY_FORM = {
  name: "", email: "", title: "",
  category: "", priority: "",
  description: "", steps: "",
};

// ─── Azure DevOps API Call ────────────────────────────────────────────────────
function buildPatch(form) {
  const p = PRIORITIES.find((x) => x.label === form.priority);
  const body = `
    <b>Reporter:</b> ${form.name} &lt;${form.email}&gt;<br/>
    <b>Category:</b> ${form.category}<br/>
    <b>Priority:</b> ${form.priority}<br/><br/>
    <b>Description:</b><br/>${form.description.replace(/\n/g, "<br/>")}<br/>
    ${form.steps ? `<br/><b>Steps to Reproduce:</b><br/>${form.steps.replace(/\n/g, "<br/>")}` : ""}
  `;
  return [
    { op: "add", path: "/fields/System.Title",                        value: `[${form.category}] ${form.title}` },
    { op: "add", path: "/fields/System.Description",                  value: body },
    { op: "add", path: "/fields/Microsoft.VSTS.Common.Priority",      value: p?.num ?? 3 },
    { op: "add", path: "/fields/System.Tags",                         value: `${form.category}; ${form.priority}; Anaplan` },
  ];
}

async function postToADO(form) {
  const type = `$${ADO.workItemType}`;
  const org = encodeURIComponent(import.meta.env.VITE_ADO_ORG);
  const proj = encodeURIComponent(import.meta.env.VITE_ADO_PROJECT);
  const url  = `ado-api/${org}/${proj}/_apis/wit/workitems/${type}?api-version=${ADO.apiVersion}`;
  
  const res  = await fetch(url, {
    method:  "POST",
    headers: {
      "Content-Type":  "application/json-patch+json",
      "Authorization": `Basic ${btoa(`:${import.meta.env.VITE_ADO_TOKEN}`)}`,
    },
    body: JSON.stringify(buildPatch(form)),
  });
  
  const responseText = await res.text();

  // 🔍 Log first 500 chars so you can see what came back
  

  if (!res.ok) {
    
    let msg = `HTTP ${res.status}`;
    try { msg = JSON.parse(responseText).message || msg; } catch {}
    throw new Error(msg);
  }
   const contentType = res.headers.get('content-type') || '';
  if (!contentType.includes('application/json')) {
    throw new Error(
      `Expected JSON response but received "${contentType}". ` +
      `Check that your org name and project name are correct in your .env file.`
    );
  }

  // Parse the text we already read (can't call res.json() after res.text())
  return JSON.parse(responseText);
}
//  return res.json();


// ─── Tiny animation hook ──────────────────────────────────────────────────────
function useMounted() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => { const t = setTimeout(() => setMounted(true), 30); return () => clearTimeout(t); }, []);
  return mounted;
}

// ─── Components ───────────────────────────────────────────────────────────────
function Label({ children, required }) {
  return (
    <label style={css.label}>
      {children}{required && <span style={{ color: "#f87171", marginLeft: 3 }}>*</span>}
    </label>
  );
}

function InputField({ label, name, type = "text", placeholder, value, onChange, error, icon, required }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
      <Label required={required}>{label}</Label>
      <div style={{ position: "relative" }}>
        {icon && <span style={css.fieldIcon}>{icon}</span>}
        <input
          type={type} placeholder={placeholder} value={value} autoComplete="off"
          onChange={(e) => onChange(name, e.target.value)}
          style={{ ...css.input, ...(icon ? { paddingLeft: 38 } : {}), ...(error ? css.inputErr : {}) }}
        />
      </div>
      {error && <span style={css.errTxt}>{error}</span>}
    </div>
  );
}

function TextareaField({ label, name, placeholder, value, onChange, error, rows = 4, required, hint }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
      <Label required={required}>{label}</Label>
      <textarea
        placeholder={placeholder} value={value} rows={rows}
        onChange={(e) => onChange(name, e.target.value)}
        style={{ ...css.textarea, ...(error ? css.inputErr : {}) }}
      />
      {hint  && <span style={css.hint}>{hint}</span>}
      {error && <span style={css.errTxt}>{error}</span>}
    </div>
  );
}

function CategorySelect({ value, onChange, error }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
      <Label required>Issue Category</Label>
      <div style={{ position: "relative" }}>
        <span style={css.fieldIcon}>{CATEGORIES.find((c) => c.value === value)?.icon || "📂"}</span>
        <select
          value={value} onChange={(e) => onChange("category", e.target.value)}
          style={{ ...css.select, paddingLeft: 38, ...(error ? css.inputErr : {}) }}
        >
          <option value="" disabled>Select a category…</option>
          {CATEGORIES.map((c) => (
            <option key={c.value} value={c.value}>{c.icon}  {c.value}</option>
          ))}
        </select>
      </div>
      {error && <span style={css.errTxt}>{error}</span>}
    </div>
  );
}

function PriorityPicker({ value, onChange, error }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      <Label required>Priority</Label>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 8 }}>
        {PRIORITIES.map((p) => {
          const active = value === p.label;
          return (
            <button key={p.label} type="button" onClick={() => onChange("priority", p.label)}
              style={{
                ...css.priBtn,
                border: `1.5px solid ${active ? p.accent : "#374151"}`,
                background: active ? `${p.accent}18` : "#1f2937",
                color:  active ? p.accent : "#6b7280",
                fontWeight: active ? 700 : 500,
                boxShadow: active ? `0 0 14px ${p.accent}40` : "none",
                transform: active ? "scale(1.05)" : "scale(1)",
              }}
            >
              <span style={{ fontSize: 20 }}>{PRIORITY_EMOJI[p.label]}</span>
              <span style={{ fontSize: 12 }}>{p.label}</span>
            </button>
          );
        })}
      </div>
      {error && <span style={css.errTxt}>{error}</span>}
    </div>
  );
}

function ProgressBar({ step }) {
  // step: 0=reporter, 1=issue, 2=extra
  const pct = ((step + 1) / 3) * 100;
  const labels = ["Reporter", "Issue Details", "Description"];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        {labels.map((l, i) => (
          <span key={l} style={{ fontSize: 11, fontWeight: 600,
            color: i <= step ? "#818cf8" : "#4b5563",
            letterSpacing: "0.5px", textTransform: "uppercase" }}>
            {i <= step ? "✓ " : `${i + 1}`}.{l}
          </span>
          ))}
      </div>
      <div style={{ height: 4, background: "#1f2937", borderRadius: 99, overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${pct}%`, background: "linear-gradient(90deg,#6366f1,#a78bfa)", borderRadius: 99, transition: "width 0.4s ease" }} />
      </div>
    </div>
  );
}

