function HistoryRow({ h }) {
  const p = PRIORITIES.find((x) => x.label === h.priority);
  return (
    <div style={css.hRow}>
      <span style={{ fontSize: 15 }}>{CATEGORIES.find(c=>c.value===h.category)?.icon ?? "📋"}</span>
      <span style={{ flex: 1, fontSize: 13, color: "#d1d5db", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", fontWeight: 500 }}>
        {h.title}
      </span>
      {p && <span style={{ fontSize: 11, fontWeight: 700, color: p.accent, background: `${p.accent}18`, padding: "2px 9px", borderRadius: 99 }}>{h.priority}</span>}
      {h.id
        ? <a href={h.url} target="_blank" rel="noreferrer" style={{ color: "#818cf8", fontSize: 12, fontWeight: 700 }}>#{h.id}</a>
        : <span style={{ color: "#f87171", fontSize: 12 }}>✗ Failed</span>}
      <span style={{ color: "#4b5563", fontSize: 11 }}>{h.time}</span>
    </div>
  );
}

// ─── Main App ─────────────────────────────────────────────────────────────────
export default function App() {
  const [form,       setForm]       = useState(EMPTY_FORM);
  const [errors,     setErrors]     = useState({});
  const [busy,       setBusy]       = useState(false);
  const [success,    setSuccess]    = useState(null); // ADO result
  const [apiErr,     setApiErr]     = useState(null);
  const [history,    setHistory]    = useState([]);
  const [showHist,   setShowHist]   = useState(false);
  const mounted = useMounted();

  const update = useCallback((key, val) => {
    setForm((f) => ({ ...f, [key]: val }));
    setErrors((e) => ({ ...e, [key]: undefined }));
  }, []);

  const validate = () => {
    const e = {};
    if (!form.name.trim())     e.name     = "Full name is required.";
    if (!form.email.trim())    e.email    = "Email address is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) e.email = "Enter a valid email.";
    if (!form.title.trim())    e.title    = "Issue title is required.";
    if (!form.category)        e.category = "Please select a category.";
    if (!form.priority)        e.priority = "Please select a priority level.";
    if (!form.description.trim()) e.description = "Please describe the issue.";
    return e;
  };

  // Derive progress step
  const step = (() => {
    if (form.description || form.steps) return 2;
    if (form.title || form.category || form.priority) return 1;
    return 0;
  })();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setBusy(true);
   
    setApiErr(null);
    
    try {
      const result = await postToADO(form);
      
      const url = result._links?.html?.href;
      
      setHistory((h) => [{
        title: form.title, category: form.category, priority: form.priority,
        id: result.id, url, time: new Date().toLocaleTimeString(),
      }, ...h.slice(0, 9)]);
      setSuccess(result);
      
    } catch (err) {
           
      setApiErr(err.message);
        setHistory((h) => [{
        title: form.title, category: form.category, priority: form.priority,
        time: new Date().toLocaleTimeString(),
      }, ...h.slice(0, 9)]);
    } finally {
      setBusy(false);
      
    }
  };

  const handleReset = () => { setForm(EMPTY_FORM); setErrors({}); setSuccess(null); setApiErr(null); };

  // ── Render: Success ──────────────────────────────────────────────────────────
  if (success) {
    
    return (
      <div style={css.root}>
        <div style={{ ...css.shell, opacity: mounted ? 1 : 0, transition: "opacity 0.4s" }}>
          <Header />
          <SuccessScreen result={success} form={form} onReset={handleReset} />
          {history.length > 0 && (
            <div style={css.histBox}>
              <button style={css.histToggle} onClick={() => setShowHist(o => !o)}>
                {showHist ? "▾" : "▸"} Submission History ({history.length})
              </button>
              {showHist && history.map((h, i) => <HistoryRow key={i} h={h} />)}
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Render: Form ─────────────────────────────────────────────────────────────
  return (
    <div style={css.root}>
      <div style={{ ...css.shell, opacity: mounted ? 1 : 0, transform: mounted ? "translateY(0)" : "translateY(16px)", transition: "all 0.45s ease" }}>
        <Header />

        {/* Status bar */}
        <div style={css.statusBar}>
          <span style={css.statusDot} />
          <span style={{ color: "#9ca3af", fontSize: 12 }}>
            Connected to <span style={{ color: "#d1d5db", fontWeight: 600 }}>{ADO.org}</span>
            {" › "}<span style={{ color: "#d1d5db", fontWeight: 600 }}>{ADO.project}</span>
            {" · "}<span style={{ color: "#818cf8", fontWeight: 600 }}>Work Item: {ADO.workItemType}</span>
          </span>
        </div>

        {/* API error */}
        {apiErr && (
          <div style={css.apiErrBox}>
            <span style={{ fontSize: 18 }}>⚠️</span>
            <span style={{ flex: 1 }}><strong>Submission failed:</strong> {apiErr}</span>
            <button onClick={() => setApiErr(null)} style={css.closeBtn}>✕</button>
          </div>
        )}

        <form onSubmit={handleSubmit} noValidate>
          {/* Progress */}
          <div style={css.section}>
            <ProgressBar step={step} />
          </div>

          {/* Section 1 — Reporter */}
          <div style={css.section}>
            <SectionHeader icon="👤" title="Reporter Information" />
            <div style={css.grid2}>
              <InputField label="Full Name"      name="name"  placeholder="e.g. Jane Smith"         value={form.name}  onChange={update} error={errors.name}  icon="👤" required />
              <InputField label="Email Address"  name="email" placeholder="jane@company.com" type="email" value={form.email} onChange={update} error={errors.email} icon="✉️" required />
            </div>
          </div>

          {/* Divider */}
          <div style={css.divider} />

          {/* Section 2 — Issue Details */}
          <div style={css.section}>
            <SectionHeader icon="🎫" title="Issue Details" />
            <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
              <InputField
                label="Issue Title" name="title"
                placeholder="Short, clear summary of the problem"
                value={form.title} onChange={update} error={errors.title} icon="📝" required
              />
              <div style={css.grid2}>
                <CategorySelect value={form.category} onChange={update} error={errors.category} />
                <div /> {/* spacer */}
              </div>
              <PriorityPicker value={form.priority} onChange={update} error={errors.priority} />
            </div>
          </div>

          {/* Divider */}
          <div style={css.divider} />

          {/* Section 3 — Description */}
          <div style={css.section}>
            <SectionHeader icon="📄" title="Description" />
            <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
              <TextareaField
                label="Detailed Description" name="description"
                placeholder="Describe the issue — what happened, what you expected, and the impact…"
                value={form.description} onChange={update} error={errors.description} rows={5} required
              />
              <TextareaField
                label="Steps to Reproduce" name="steps"
                placeholder={"1. Navigate to…\n2. Click on…\n3. Observe that…"}
                value={form.steps} onChange={update} rows={4}
                hint="Optional — helps the team reproduce the issue faster."
              />
            </div>
          </div>

          {/* Submit */}
          <div style={{ padding: "0 28px 28px" }}>
            <button type="submit" disabled={busy} style={{ ...css.submitBtn, ...(busy ? css.submitBusy : {}) }}>
              {busy ? (
                <span style={{ display: "flex", alignItems: "center", gap: 10, justifyContent: "center" }}>
                  <span style={css.spinner} />
                  Submitting to Azure DevOps…
                </span>
              ) : "🚀  Submit Support Ticket"}
            </button>
          </div>
        </form>

        {/* History */}
        {history.length > 0 && (
          <div style={css.histBox}>
            <button style={css.histToggle} onClick={() => setShowHist(o => !o)}>
              {showHist ? "▾" : "▸"} Submission History ({history.length})
            </button>
            {showHist && history.map((h, i) => <HistoryRow key={i} h={h} />)}
          </div>
        )}
        {history.length > 0 && (
        <p style={css.footer}>
          Your ticket has been submitted.
        </p>
        )}
      </div>

      {/* Keyframe injection */}
      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes pulse-ring { 0%,100% { box-shadow: 0 0 0 0 #6366f140; } 50% { box-shadow: 0 0 0 14px #6366f100; } }
        select option { background: #1f2937; color: #f9fafb; }
        input::placeholder, textarea::placeholder { color: #4b5563; }
        input:focus, textarea:focus, select:focus { border-color: #6366f1 !important; outline: none; box-shadow: 0 0 0 3px #6366f133; }
        button:hover:not(:disabled) { filter: brightness(1.08); }
        ::-webkit-scrollbar { width: 6px; } ::-webkit-scrollbar-track { background: #111827; } ::-webkit-scrollbar-thumb { background: #374151; border-radius: 99px; }
      `}</style>
    </div>
  );
}

